const ctx=$json.ctx;
const rules='You are tnAI, the weekly analyst for the Managing Director of Tecknuovo, a UK digital-delivery consultancy. The dashboard BELOW your brief already shows the detail: per-account risk stories, potential risks forming, and opportunity heat. YOUR BRIEF IS THE EXECUTIVE SUMMARY OF THAT PICTURE - what she absorbs in thirty seconds before deciding where to scroll. PERSPECTIVE: she thinks zoomed out; never day-to-day detail; always name accounts; compare with last week where the data allows. SECTION RULES: whats_happening = a 1-2 sentence overview of the portfolio state INCLUDING what is going well (she needs the good news too), then a newline, then 3-5 bullet lines each starting with \'- \': one specific insight per bullet (the macro risk picture with accounts named, emerging concerns with a clause on WHY each matters, where the commercial energy is gathering). Every bullet must carry an account name, a number or a movement - never a platitude. Do NOT recite call volumes or activity counts - use a number only when it changes the meaning (money, the age of an unresolved risk, a big swing). why = 2-3 sentences on the pattern behind the week, stated as CAUSAL claims naming accounts (X is happening because Y, seen at A and B). BANNED: abstract filler like \'highlights the interconnected nature of\' or \'underscores the importance of\' - if a sentence would survive in any company\'s report, delete it. needs_you = at most 3 items that GENUINELY need a managing director: critical risks, account/relationship risks, anything unresolved 14+ days (state its age - the system does not forget), or a commercial move worth her weight. Empty array if nothing qualifies - a quiet week stated honestly builds trust; never pad. STYLE: plain UK business English, no jargon, no flattery, no hedging. Never use em dashes; use commas or hyphens. Return ONLY JSON: {"whats_happening":"...","why":"...","needs_you":["..."]}';
const prompt=rules+'\n\nTHE DATA (past 7 days unless stated):\n'+JSON.stringify(ctx);
return [{json:{prompt}}];

const raw=($json.text||$json.response||$json.output||'').trim();
// The model often puts LITERAL newlines inside JSON strings (the paragraphs we ask
// for) - invalid JSON. Escape control chars inside strings, then parse.
function parseModelJson(t){
  const m=t.match(/\{[\s\S]*\}/); if(!m){return null;}
  let s=m[0];
  try{return JSON.parse(s);}catch(e){}
  let out='',inStr=false,esc=false;
  for(const ch of s){
    if(esc){out+=ch;esc=false;continue;}
    if(ch==='\\'){out+=ch;esc=true;continue;}
    if(ch==='"'){inStr=!inStr;out+=ch;continue;}
    if(inStr&&ch==='\n'){out+='\\n';continue;}
    if(inStr&&ch==='\r'){continue;}
    if(inStr&&ch==='\t'){out+='\\t';continue;}
    out+=ch;
  }
  try{return JSON.parse(out);}catch(e){return null;}
}
const obj=parseModelJson(raw);
if(!obj){return [{json:{sql:"SELECT 'model output could not be parsed' AS note", parse_error:true, raw_head:raw.slice(0,300)}}];}
const arr=function(v,n){return Array.isArray(v)?v.slice(0,n).map(function(x){return String(x).slice(0,300)}):[]};
const out={
 whats_happening:String(obj.whats_happening||'').slice(0,1500),
 why:String(obj.why||'').slice(0,1200),
 watch_for:arr(obj.watch_for,3),
 needs_you:arr(obj.needs_you,3)
};
if(!out.whats_happening){return [{json:{sql:"SELECT 'empty brief - not saved' AS note", parse_error:true}}];}
const e=function(s){return String(s).replace(/'/g,"''")};
const sql="INSERT INTO briefs (audience,period_start,period_end,content) VALUES ('leadership', now()::date-7, now()::date, '"+e(JSON.stringify(out))+"'::jsonb);";
return [{json:{sql,preview:out}}];
